#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* getNode(Node** pool, int id) {
    if (pool[id] == NULL) {
        pool[id] = (Node*)malloc(sizeof(Node));
        pool[id]->val = id;
        pool[id]->left = pool[id]->right = NULL;
    }
    return pool[id];
}

int isMirror(Node* a, Node* b) {
    if (!a && !b) return 1;
    if (!a || !b) return 0;
    return isMirror(a->left, b->right) && isMirror(a->right, b->left);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node* nodes[10001] = {0}; // N ≤ 10000
        int isChild[10001] = {0};
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir; scanf("%d %d %c", &p, &c, &dir);
            Node* parent = getNode(nodes, p);
            Node* child  = getNode(nodes, c);
            if (dir == 'L') parent->left = child; else parent->right = child;
            isChild[c] = 1;
        }
        int rootId = 1;
        for (int i = 1; i <= N; ++i) if (!isChild[i]) { rootId = i; break; }
        Node* root = nodes[rootId];
        if (isMirror(root ? root->left : NULL, root ? root->right : NULL))
            printf("YES\n");
        else
            printf("NO\n");
        // free memory (optional for contest)
        for (int i = 1; i <= N; ++i) if (nodes[i]) free(nodes[i]);
    }
    return 0;
}

