import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { this.val = v; }
    }

    static Node getNode(Node[] pool, int id) {
        if (pool[id] == null) pool[id] = new Node(id);
        return pool[id];
    }

    static boolean isMirror(Node a, Node b) {
        if (a == null && b == null) return true;
        if (a == null || b == null) return false;
        return isMirror(a.left, b.right) && isMirror(a.right, b.left);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Node[] nodes = new Node[N + 1];
            boolean[] isChild = new boolean[N + 1];
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                Node parent = getNode(nodes, p);
                Node child = getNode(nodes, c);
                if (dir == 'L') parent.left = child; else parent.right = child;
                isChild[c] = true;
            }
            int rootId = 1;
            for (int i = 1; i <= N; i++) if (!isChild[i]) { rootId = i; break; }
            Node root = nodes[rootId];
            boolean ok = isMirror(root == null ? null : root.left, root == null ? null : root.right);
            out.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

