import sys

def is_mirror(a, b):
    if a is None and b is None:
        return True
    if a is None or b is None:
        return False
    return is_mirror(a[1], b[2]) and is_mirror(a[2], b[1])

# node representation: [val, left, right] where left/right are either None or similar list

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(T):
        N = int(data[idx].strip()); idx += 1
        nodes = [None] * (N + 1)
        is_child = [False] * (N + 1)
        for __ in range(N - 1):
            p_str, c_str, dir = data[idx].split(); idx += 1
            p = int(p_str); c = int(c_str)
            if nodes[p] is None:
                nodes[p] = [p, None, None]
            if nodes[c] is None:
                nodes[c] = [c, None, None]
            if dir == 'L':
                nodes[p][1] = nodes[c]
            else:
                nodes[p][2] = nodes[c]
            is_child[c] = True
        root_id = 1
        for i in range(1, N + 1):
            if not is_child[i]:
                root_id = i
                break
        root = nodes[root_id]
        if root is None:
            out_lines.append('YES')
        else:
            ok = is_mirror(root[1], root[2])
            out_lines.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

